oggle.BackgroundColor3 = UIConfig.ActiveColor TweenService:Create(Slider, tweenInfo, {Position = UDim2.new(0, 34, 0.5, -12)}):Play() else Toggle.BackgroundColor3 = Color3.fromRGB(45, 45, 45) TweenService:Create(Slider, tweenInfo, {Position = UDim2.new(0, 2, 0.5, -12)}):Play() end end) return Toggle, ToggleBtn end -- Auto Farm System local function AutoFarmSystem() while Features.AutoFarm.Enabled do task.wait(0.5) pcall(function() local questNPC = nil for _, v in next, game:GetService("Workspace"):GetDescendants() do if v.Name:find("Quest") and v:IsA("Model") then questNPC = v break end end if questNPC then local targetPos = questNPC.PrimaryPart.Position + Vector3.new(0, 5, 0) local playerPos = Player.Character.HumanoidRootPart.Position local tweenInfo = TweenInfo.new(2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out) local tween = TweenService:Create(Player.Character.HumanoidRootPart, tweenInfo, {CFrame = CFrame.new(targetPos)}) tween:Play() task.wait(0.5) for _, mob in next, game:GetService("Workspace"):GetDescendants() do if mob.Name:find("Mob") and mob:FindFirstChild("Humanoid") then local dist = (Player.Character.HumanoidRootPart.Position - mob.HumanoidRootPart.Position).Magnitude if dist < 100 then Player.Character.Humanoid:MoveTowards(mob.HumanoidRootPart.Position) task.wait(0.1) if UserInputService:IsMouseButtonPressed(1) then break end end end end end end) end end -- Auto Mastery System local function AutoMasterySystem() while Features.AutoMastery.Enabled do task.wait(0.5) pcall(function() local target = nil for _, v in next, game:GetService("Workspace"):GetDescendants() do if v:FindFirstChild("Humanoid") and v.Name:find("Mob") then local dist = (Player.Character.HumanoidRootPart.Position - v.HumanoidRootPart.Position).Magnitude if dist < 50 then target = v break end end end if target and target.Humanoid.Health > 1 then if Features.AutoMastery.Type == "Fruit" then pcall(function() game:GetService("ReplicatedStorage"):FindFirstChild("UseAbility"):FireServer(1) end) end end end) end end -- Auto Stats System local function AutoStatsSystem() while Features.AutoStats.Enabled do task.wait(1) pcall(function() local stats = Player:FindFirstChild("leaderstats") if stats then local points = stats:FindFirstChild("Stats") if points and points.Value > 0 then for _, statName in next, Features.AutoStats.Priority do local stat = stats:FindFirstChild(statName) if stat then stat.Value = stat.Value + 1 points.Value = points.Value - 1 break end end end end end) end end -- ESP System local ESPGui = nil local ESPLabels = {} local function CreateESPSystem() ESPGui = Instance.new("ScreenGui") ESPGui.Name = "ESPGui" ESPGui.ResetOnSpawn = false ESPGui.Parent = Player:WaitForChild("PlayerGui") local espLoop = coroutine.wrap(function() while true do task.wait(0.1) if Features.PlayerESP.Enabled then for _, player in next, game:GetService("Players"):GetPlayers() do if player ~= Player and player.Character then local hrp = player.Character:FindFirstChild("HumanoidRootPart") if hrp then local onScreen, screenPos = workspace.CurrentCamera:WorldToScreenPoint(hrp.Position) if onScreen then local label = ESPLabels[player.UserId] if not label then label = Instance.new("TextLabel") label.Size = UDim2.new(0, 150, 0, 40) label.BackgroundTransparency = 1 label.TextColor3 = Color3.fromRGB(255, 255, 255) label.TextStrokeTransparency = 0 label.Font = Enum.Font.Gotham label.ZIndex = 10 label.Parent = ESPGui ESPLabels[player.UserId] = label end label.Position = UDim2.new(0, screenPos.X - 75, 0, screenPos.Y - 50) local dist = (Player.Character.HumanoidRootPart.Position - hrp.Position).Magnitude local humanoid = player.Character:FindFirstChild("Humanoid") local health = humanoid and humanoid.Health or 0 label.Text = string.format("%s\n%.0fm\nHP: %d", player.Name, dist, health) end end end end end if Features.FruitESP.Enabled then for _, fruit in next, game:GetService("Workspace"):GetDescendants() do if fruit.Name:find("Blox Fruit") and fruit:IsA("Model") then local primary = fruit:FindFirstChild("PrimaryPart") if primary then local onScreen, screenPos = workspace.CurrentCamera:WorldToScreenPoint(primary.Position) if onScreen then local label = ESPLabels[fruit.PrimaryPart] if not label then label = Instance.new("TextLabel") label.Size = UDim2.new(0, 120, 0, 30) label.BackgroundTransparency = 1 label.TextColor3 = Color3.fromRGB(255, 215, 0) label.TextStrokeTransparency = 0 label.Font = Enum.Font.GothamBold label.ZIndex = 10 label.Parent = ESPGui ESPLabels[fruit.PrimaryPart] = label end label.Position = UDim2.new(0, screenPos.X - 60, 0, screenPos.Y - 40) local dist = (Player.Character.HumanoidRootPart.Position - primary.Position).Magnitude label.Text = string.format("🍎 %s\n%.0fm", fruit.Name:match("(.+)-") or "Fruit", dist) end end end end end if Features.SwordDealerESP.Enabled then for _, npc in next, game:GetService("Workspace"):GetDescendants() do if npc.Name:find("Legendary") and npc.Name:find("Sword") then local hrp = npc:FindFirstChild("HumanoidRootPart") if hrp then local onScreen, screenPos = workspace.CurrentCamera:WorldToScreenPoint(hrp.Position) if onScreen then local alert = ESPGui:FindFirstChild("DealerAlert") if not alert then alert = Instance.new("TextLabel") alert.Name = "DealerAlert" alert.Size = UDim2.new(0, 400, 0, 100) alert.Position = UDim2.new(0.5, -200, 0.2, 0) alert.BackgroundColor3 = Color3.fromRGB(139, 92, 246) alert.Text = "⚔️ SWORD DEALER SPAWNED! ⚔️" alert.TextColor3 = Color3.fromRGB(255, 255, 255) alert.TextStrokeTransparency = 0 alert.Font = Enum.Font.GothamBold alert.TextSize = 36 alert.ZIndex = 100 alert.Parent = ESPGui end end end end end else local alert = ESPGui:FindFirstChild("DealerAlert") if alert then alert:Destroy() end end end end) coroutine.resume(espLoop) end -- Teleport System local Teleports = { Sea1 = { Prelude = Vector3.new(-50, 100, 0), Jail = Vector3.new(-200, 100, -200), Mysterious = Vector3.new(500, 100, 500) }, Sea2 = { Risky = Vector3.new(1000, 100, 1000), Fried = Vector3.new(1500, 100, 1500), Alpine = Vector3.new(2000, 100, 2000) }, Sea3 = { GreenZone = Vector3.new(3000, 100, 3000), Hunting = Vector3.new(3500, 100, 3500), RedZone = Vector3.new(4000, 100, 4000) } } local function TeleportTo(location) pcall(function() local player = Player.Character if player then local hrp = player:FindFirstChild("HumanoidRootPart") if hrp then hrp.CFrame = CFrame.new(location) end end end) end -- Fruit Sniper System local function FruitSniperSystem() while Features.FruitSniper.Enabled do task.wait(0.05) pcall(function() local dealer = nil for _, v in next, game:GetService("Workspace"):GetDescendants() do if v.Name:find("Blox Fruit Dealer") then dealer = v break end end if dealer then for _, fruit in next, dealer:GetDescendants() do if fruit.Name:find("Blox Fruit") and fruit.Name:find(Features.FruitSniper.TargetFruit) then pcall(function() game:GetService("ReplicatedStorage"):FindFirstChild("BuyFruit"):FireServer(fruit) end) if not Features.FruitSniper.AutoRebuy then Features.FruitSniper.Enabled = false end break end end end end) end end -- Initialize Script local ScreenGui, MainFrame = CreateMainFrame() local ToggleBtn = CreateToggleButton(ScreenGui) local CloseBtn = MainFrame:FindFirstChildWhichIsA("TextButton") -- Toggle Button Logic ToggleBtn.MouseButton1Click:Connect(function() MainFrame.Visible = not MainFrame.Visible ToggleBtn.Visible = not ToggleBtn.Visible end) -- Close Button Logic local function CreateCloseBtn() local btn = Instance.new("TextButton") btn.Size = UDim2.new(0, 35, 0, 35) btn.Position = UDim2.new(1, -45, 0, 10) btn.BackgroundColor3 = Color3.fromRGB(239, 68, 68) btn.BorderSizePixel = 0 btn.ZIndex = 100 btn.Parent = MainFrame local corner = Instance.new("UICorner") corner.CornerRadius = UDim.new(0.5, 0) corner.Parent = btn btn.MouseButton1Click:Connect(function() MainFrame.Visible = false ToggleBtn.Visible = true end) return btn end -- Cleanup Function local function Cleanup() if ScreenGui then ScreenGui:Destroy() end if ESPGui then ESPGui:Destroy() end for _, label in next, ESPLabels do if label then label:Destroy() end end end -- Start All Systems coroutine.wrap(function() CreateESPSystem() AutoFarmSystem() AutoMasterySystem() AutoStatsSystem() FruitSniperSystem() end)() -- Script Loaded print("[BloxFruitsHub] Script Loaded Successfully!") print("[BloxFruitsHub] All Features Ready!") print("[BloxFruitsHub] Click the toggle button to minimize!")
